    {
      "parameters": {
        "functionCode": "const fs = require('fs');\nconst crypto = require('crypto');\nconst path = '/data/dedupe_store.json';\nlet store = { urls: {}, titles: {}, hashes: {} };\ntry { store = JSON.parse(fs.readFileSync(path, 'utf8')); } catch(e) {}\nconst now = new Date().toISOString();\nconst newItems = [];\nfunction isOlderThan7Days(ts) {\n  const diff = Date.now() - new Date(ts).getTime();\n  return diff > 7 * 24 * 60 * 60 * 1000;\n}\nfor (const item of items) {\n  const normTitle = item.title.toLowerCase().replace(/[^a-z0-9\\s]/g, '').trim();\n  if (store.urls[item.url] && !isOlderThan7Days(store.urls[item.url])) { item.skip_reason = 'duplicate_url'; continue; }\n  if (store.titles[normTitle] && !isOlderThan7Days(store.titles[normTitle])) { item.skip_reason = 'duplicate_title'; continue; }\n  const contentHash = crypto.createHash('sha1').update(item.raw_content.substring(0, 500)).digest('hex');\n  if (store.hashes[contentHash] && !isOlderThan7Days(store.hashes[contentHash])) { item.skip_reason = 'duplicate_content'; continue; }\n  newItems.push(item);\n  store.urls[item.url] = now;\n  store.titles[normTitle] = now;\n  store.hashes[contentHash] = now;\n}\nfunction prune(obj) { for (const key in obj) { if (isOlderThan7Days(obj[key])) delete obj[key]; } }\nprune(store.urls); prune(store.titles); prune(store.hashes);\nfs.writeFileSync(path, JSON.stringify(store, null, 2));\nreturn newItems;"
      },
      "id": "dedupe",
      "name": "Deduplicate",
      "type": "n8n-nodes-base.function",
      "typeVersion": 1,
      "position": [1050, 300]
    },
    {
      "parameters": {
        "functionCode": "const itemsWithScore = items.map(item => {\n  let score = 0;\n  const title = (item.title || '').toLowerCase();\n  const content = (item.raw_content || '').toLowerCase();\n  const combined = title + ' ' + content;\n  const cred = { rss: 15, github: 20, youtube: 12, other: 5 }[item.source_type] || 5; score += cred;\n  const keywords = ['ollama','n8n','local','llama.cpp','open webui','comfyui','agents','agent orchestration','workflow automation','privacy','self-hosted','gguf','quantization','gpu inference','local ai','open-source model','model release','benchmark','llama','mistral','gemma','phi','claude','gpt','deepseek','perplexity','hugging face'];\n  let kwMatches = 0; for (const kw of keywords) { if (combined.includes(kw)) kwMatches++; }\n  score += Math.min(kwMatches * 2, 20);\n  if (['ollama','n8n','llama.cpp','comfyui','open webui'].some(k => title.includes(k))) score += 10;\n  const pub = new Date(item.published_at);\n  const hoursAgo = (Date.now() - pub.getTime()) / (1000 * 60 * 60);\n  if (hoursAgo < 6) score += 15; else if (hoursAgo < 12) score += 10; else if (hoursAgo < 24) score += 5;\n  let tech = 0;\n  if (title.includes('release') || title.includes('version')) tech += 5;\n  if (title.includes('benchmark') || title.includes('eval')) tech += 5;\n  if (content.includes('```') || content.includes('code block')) tech += 5;\n  if (title.includes('how to') || title.includes('tutorial')) tech += 3;\n  score += Math.min(tech, 15);\n  const actionWords = ['install','upgrade','download','setup','docker','configure','run','execute'];\n  let act = 0; for (const w of actionWords) { if (combined.includes(w)) act++; }\n  score += Math.min(act, 10);\n  if (item.source_type === 'github' || ['huggingface','anthropic','openai','ollama'].some(b => item.source_name.toLowerCase().includes(b))) score += 10;\n  if (item.source_type === 'github' || combined.includes('open-source') || combined.includes('open source') || combined.includes('local') || combined.includes('self-hosted')) score += 10;\n  score = Math.min(score, 100);\n  item.score = score;\n  item.category = (function(){\n    const t = combined;\n    if (/openai|anthropic|google|meta|xai|microsoft|perplexity|deepmind|mistral/.test(t)) return 'major_lab';\n    if (/ollama|llama.cpp|gguf|local|self-hosted|inference/.test(t)) return 'local_ai';\n    if (/n8n|openclaw|agents|workflow|automation|orchestration/.test(t)) return 'agents_automation';\n    if (/cursor|copilot|claude code|cline|ai coding|ide/.test(t)) return 'ai_coding';\n    if (/comfyui|stable diffusion|midjourney|dall|generative media|video|audio|music/.test(t)) return 'generative_media';\n    if (item.source_type === 'github') return 'github_release';\n    return 'other';\n  })();\n  return item;\n});\nreturn itemsWithScore;"
