      "parameters": {
        "functionCode": "const OLLAMA_URL = $env.OLLAMA_BASE_URL || 'http://host.docker.internal:11434';\nconst items = [];\nfor (const item of $input.all()) {\n  if (item.json.score >= 70) {\n    try {\n      const prompt = `You are a technical news summarizer. Write a concise 2-3 sentence summary focusing on:\\n- What changed or was released\\n- Technical details (versions, features, benchmarks)\\n- Practical impact for a local AI/automation builder\\n- Avoid hype and fluff\\n\\nTitle: ${item.json.title}\\nContent: ${item.json.raw_content.substring(0, 3000)}`;\n      const response = await $fetch(OLLAMA_URL + '/api/generate', {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json' },\n        body: JSON.stringify({\n          model: 'llama3.2:3b',\n          prompt: prompt,\n          stream: false,\n          options: { temperature: 0.3 }\n        })\n      });\n      const data = typeof response === 'string' ? JSON.parse(response) : response;\n      item.json.summary = data.response || data.message?.content || 'Summary failed';\n    } catch (err) {\n      console.error('Ollama error:', err);\n      item.json.summary = item.json.raw_content.substring(0, 200) + '...';\n    }\n  } else {\n    item.json.summary = '';\n  }\n  items.push(item);\n}\nreturn items;"
      },
      "id": "summarize",
      "name": "Summarize with Ollama",
      "type": "n8n-nodes-base.function",
      "typeVersion": 1,
      "position": [1450, 300]
    },
    {
      "parameters": {
        "functionCode": "const categories = { must_show: [], builder_show: [], watch_later: [], skipped: [] };\nconst byCategory = { major_lab: [], local_ai: [], agents_automation: [], ai_coding: [], generative_media: [], github_release: [], other: [] };\nfor (const item of $input.all()) {\n  const json = item.json;\n  if (json.score >= 85) categories.must_show.push(json);\n  else if (json.score >= 70) categories.builder_show.push(json);\n  else if (json.score >= 50) categories.watch_later.push(json);\n  else categories.skipped.push(json);\n  byCategory[json.category].push(json);\n}\ncategories.must_show.sort((a,b) => b.score - a.score);\ncategories.builder_show.sort((a,b) => b.score - a.score);\nconst now = new Date();\nconst dateStr = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });\nconst edition = now.getHours() < 12 ? 'Morning' : 'Evening';\nlet markdown = `# AI News Briefing – ${dateStr} (${edition} Edition)\\n\\n`;\nmarkdown += '## Executive Summary\\n';\nif (categories.must_show.length > 0) {\n  const top = categories.must_show.slice(0, 3);\n  for (const item of top) {\n    markdown += `- ${item.title} (${item.source_name}): ${item.summary || item.raw_content.substring(0, 150)}...\\n`;\n  }\n} else { markdown += 'No major updates today.\\n'; }\nmarkdown += '\\n';\nfunction formatItem(item) {\n  const summary = item.summary || item.raw_content.substring(0, 150) + '...';\n  return `- **${item.title}** (${item.source_name})\\n  ${summary}\\n  <${item.url}>\\n`;\n}\nconst sectionOrder = ['major_lab','local_ai','agents_automation','ai_coding','generative_media','github_release'];\nconst sectionTitles = { major_lab: 'Major Lab & Product Updates', local_ai: 'Local & Open-Source AI', agents_automation: 'Agents & Automation', ai_coding: 'AI Coding Tools', generative_media: 'Generative Media', github_release: 'GitHub Releases Watch' };\nfor (const cat of sectionOrder) {\n  const items = byCategory[cat].filter(i => i.score >= 70).sort((a,b) => b.score - a.score);\n  if (items.length === 0) continue;\n  markdown += `## ${sectionTitles[cat]}\\n`;\n  for (const item of items) { markdown += formatItem(item); }\n  markdown += '\\n';\n}\nconst topMust = categories.must_show.slice(0,5);\nif (topMust.length) {\n  markdown += '## Must-Know Updates\\n';\n  for (const item of topMust) { markdown += formatItem(item); }\n}\nif (categories.watch_later.length) {\n  markdown += '## Watch Later\\n';\n  for (const item of categories.watch_later) { markdown += `- ${item.title} (${item.source_name}) [score: ${item.score}]\\n`; }\n  markdown += '\\n';\n}\nmarkdown += `## Skipped\\n- ${categories.skipped.length} items filtered as low signal.\\n`;\nconst actionItems = categories.must_show.filter(i => /install|upgrade|download|setup|docker/.test(i.raw_content.toLowerCase()));\nif (actionItems.length) {\n  markdown += '## Action Items\\n';\n  for (const item of actionItems) { markdown += `- ${item.title}\\n`; }\n}\nmarkdown += `\\n---\\n*Generated: ${now.toISOString()} • Items processed: ${$input.all().length} • Must-know: ${categories.must_show.length} • Watch later: ${categories.watch_later.length} • Skipped: ${categories.skipped.length}*\\n`;\nreturn [{ json: { markdown } }];"
      },
